   329→static int nfp_ct_merge_act_check(struct nfp_fl_ct_flow_entry *pre_ct_entry,
   330→				  struct nfp_fl_ct_flow_entry *post_ct_entry,
   331→				  struct nfp_fl_ct_flow_entry *nft_entry)
   332→{
   333→	struct flow_action_entry *act;
